  ('heelevel3-6e2f88c7-moex-00132', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '人民因正當使用合法藥物所生之藥害，得依藥害救濟法請求救濟，此之所謂「救濟」，其法律上定 性為何？', '["民事損害賠償", "國家賠償", "刑事訴訟附帶民事賠償", "基於社會衡平所為之行政補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00133', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲男駕車載女友乙以及乙的母親丙到郊外餐廳，想要討論甲、乙計畫結婚
之事。車子行經十字路口，甲無任何疏失竟遭開車闖紅燈的丁撞擊，甲、
乙兩人僅受輕傷，丁則是受到驚嚇，全身癱軟，而坐在甲車後座的丙由於
直接受撞擊，多處骨折且血流不止。乙女本來已經拿出手機要呼叫救護車
將丙送醫急救，但甲想到丙一直阻攔他跟乙的婚事，遂勸乙不要救丙。乙
因為深愛甲，很想跟甲雙宿雙飛，雖明知不將丙送醫，丙將丟掉性命，但
仍狠下心來，不招救護車將丙送醫，嗣後丙果然因為延誤送醫流血過多死
亡。試問甲、乙觸犯刑法上何罪名？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00134', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲沒有大客車駕駛執照，聽聞擔任遊覽車司機的朋友乙因為生病無法上
班，甲為了既能幫助朋友，自己也能賺點外快，便到乙任職公司佯稱自己
有大客車駕駛執照，且願意幫乙代班。遊覽車公司老闆見甲一臉老實，信
以為真，便讓甲開車出團。孰料，沒開過遊覽車的甲開車技術並不足以駕
駛遊覽車，因為不熟悉大客車後視鏡的使用，在轉彎時雖然已經極為注
意，但仍輾斃一旁騎機車的老翁A。試問甲有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00135', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '律師甲受某政治人物的妻子A委任，為A處理案件。甲將部分卷宗帶回家
中閱讀，但因疏忽將卷宗打開放在桌上，不料竟被甲的妻子乙看到一文
件，證實坊間傳聞A被其丈夫家暴一事。乙平常即對該政治人物的言論極
為不滿，遂向甲「曉以大義」，要求將此文件內容傳給媒體報導公諸於世。
甲禁不起乙的勸說洗腦，便跟乙共同將此文件影印後寄給報社刊登。嗣後
A對甲、乙兩人提出告訴，試問甲、乙有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00136', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲對乙佯稱自己是某黑幫的堂主，手下小弟都兇狠無比，因為前陣子殺了
人，現在正在跑路，想要乙贊助一萬元的跑路費，不然就要叫手下小弟把
乙帶到山上殺死埋掉。乙聽到後驚恐無比，遂湊了一萬元交給甲。嗣經證
實甲事實上只是個小混混，平時只敢做點雞鳴狗盜之事，甲當時對乙所說
殺死埋掉，只是為了唬弄乙，意欲得財而已。試問甲有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00137', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-d7e58de3', 'sub-heelevel3-6e2f88c7-06', NULL, 'essay', 'A股份有限公司（以下稱A公司）為公開發行公司，資本額為新臺幣（下
同）1億元、每股面額為10元。關於公司盈餘分派A公司章程第18條第1項、
第2項分別規定「本公司年度總決算如有盈餘，其分派如下：1.提繳稅捐。
2.彌補累積虧損。3.預估保留員工與董事酬勞。4.提列百分之十之法定盈
餘公積。5.如尚有盈餘，由董事會擬具分派議案，以發行新股方式為之時，
應提請股東會決議後分派之。」、「本公司依公司法第240條第5項規定，將
應分派股息及紅利授權董事會以三分之二以上董事之出席，並得出席過
半數同意以發放現金之方式為之，並報告股東會。」甲為A公司股東，持
有無表決權特別股11萬股，認為公司現金股利分派決定權應回歸至股東
會，故而在本年度股東常會召開前向董事會提出以下議案，要旨略為「刪
除章程第18條第1項第5款『以發行新股方式為之時，應』等文字」、「刪除
第18條第2項」。惟甲前開提案在A公司董事會審查後被拒絕列入議案，理
由略為「一、甲為無表決權股東，並無提案權；二、提案非股東會所得決
議者；三、提案數量超過一項。」關於A公司董事會拒絕甲之提案，請詳
細分析是否有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "02f44ec67dc2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1217", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00138', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-d7e58de3', 'sub-heelevel3-6e2f88c7-06', NULL, 'essay', '甲為清償對乙之債務，簽發未記載金額之本票交予乙，並與乙約定於新臺
幣（下同）10萬元範圍內得視債務返還狀況乙自由補充。詎料，乙事後補
充填寫20萬元後再背書轉讓予不知情之丙，作為其購買二手汽車之價金。
丙取得本票後再以18萬元為對價，轉讓予知悉甲、乙間前開約定之丁。執
票人丁向甲請求給付票款時，甲得否主張「本票簽發時未記載金額，缺少
應記載事項而無效」、「乙違反甲、乙間之補充約定」、「丁知悉甲、乙間之
補充約定」等抗辯，拒絕給付票款？請仔細分析並具體作答。（25分）
33170', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "02f44ec67dc2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1217", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00139', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-d7e58de3', 'sub-heelevel3-6e2f88c7-06', NULL, 'essay', '甲於2018年3月1日時，以自己為被保險人，向X保險公司（下稱X公司）
投保人壽保險附加健康保險，約定保險費為年繳，繳費期限為每年之3月
1日，繳費方式為X公司寄發帳單後，由甲自行到金融機構或便利超商繳
費。2022年2月初時，X公司寄發當年度之繳費通知書，甲並未繳納，X公
司乃於到期日後同年3月10日發出催告通知，經甲住所之大廈管理員於同
年3月15日收取並轉交甲，但甲疏未注意而未處理。於同年11月初時，甲
自覺身體有異狀，向X公司詢問保險事宜，始知未繳費而契約已停效之事
實，並向保險公司申請復效。X公司接受甲復效之申請隔日，即要求甲到
指定醫療機構體檢並提供體檢報告供其審查。甲於體檢時，發現有胰臟
癌，腫瘤大小約二公分，胰臟癌成長到二公分大小約需三年之時間。甲提
供體檢報告予X公司，X公司於二日後，即以甲有胰臟癌，屬於其會拒保
之體況，故拒絕其復效。試問：依保險法規定，X公司拒絕甲復效之主張
有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "02f44ec67dc2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1217", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00140', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-d7e58de3', 'sub-heelevel3-6e2f88c7-06', NULL, 'essay', 'X公司擁有價值新臺幣（下同）2,000萬元之A船舶，於2023年1月時與甲締
約，以其所有之A船舶，自菲律賓宿霧港出發，載運甲託運的貨物至臺灣
臺北港，運費30萬元，其中20萬元，甲與X公司締約時即已付款。A船舶
抵達臺北港時，因船舶發生故障而遲延到港導致甲有損失50萬元；X公司
於此趟航行亦積欠船員乙、丙、丁等人薪資各50萬元。於A船舶抵達臺北
港時，X公司即委由戊進行修繕，修繕費用500萬元。X公司於2022年時，
即以A船舶設定船舶抵押權向自然人己借款1,500萬元。於戊將A船舶修繕
完畢而尚未交付於X公司時，X公司因無力支付500萬元之修繕費用及其他
債務，A船舶遂被拍賣，拍得價金2,000萬元，此時，X公司所有財產僅剩
A船舶之拍賣價金及甲未付之運費。甲主張其雖積欠X公司運費10萬元，
但X公司之遲延亦造成50萬元之損失，故其得以主張抵銷；船舶抵押權人
己亦主張就A船舶拍得之價金於其債權之1,500萬元內全額優先受償。試
具明理由說明甲、己之主張有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "02f44ec67dc2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1217", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00141', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲男與乙女結婚數年後，甲男以乙女與丙男有婚外情，訴請判決離婚。甲
男起訴後，並追加聲明謂，請求法院依夫妻剩餘財產差額分配請求權，判
決乙女應給付甲男新臺幣（下同）300萬元；並請求乙女返還其代為墊付
乙女年邁父母居住於安養中心費用之不當得利30萬元。同時，甲男請求追
加第三人丙男為共同被告，主張丙男妨害家庭之行為，致甲男產生名譽上
重大損害，請求法院判決乙、丙應連帶給付甲男200萬元。試問：受訴法
院對甲男聲明之各項追加，如何審理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
